@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: strawberry.scalars.Decimal

    @strawberry.field
    def reviews(self, info) -> List[Review]:
        return [
            Review(id=r.id, rating=r.rating, comment=r.comment, author=r.author)
            for r in self._orm.reviews
        ]

    @strawberry.field
    def sellers(self, info) -> List[Seller]:
        return [
            Seller(id=s.id, name=s.name, website=s.website)
            for s in self._orm.sellers
        ]

    @strawberry.field
    def categories(self, info) -> List[Category]:
        return [Category(id=c.id, name=c.name) for c in self._orm.categories]

    @strawberry.field
    def images(self, info) -> List[Image]:
        return [Image(id=i.id, url=i.url, alt_text=i.alt_text) for i in self._orm.images]

    _orm: ProductModel = strawberry.field(init=False, repr=False, default=None)


def to_product_type(product: ProductModel) -> Product:
    obj = Product(
        id=product.id,
        name=product.name,
        description=product.description,
        price=product.price,
    )
    object.__setattr__(obj, "_orm", product)
    return obj


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info) -> List[Product]:
        db: Session = next(get_db())
        try:
            products = (
                db.execute(
                    select(ProductModel).options(
                        selectinload(ProductModel.reviews),
                        selectinload(ProductModel.sellers),
                        selectinload(ProductModel.categories),
                        selectinload(ProductModel.images),
                    )
                )
                .scalars()
                .all()
            )
            return [to_product_type(p) for p in products]
        finally:
            db.close()

    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        db: Session = next(get_db())
        try:
            product = (
                db.execute(
                    select(ProductModel)
                    .where(ProductModel.id == id)
                    .options(
                        selectinload(ProductModel.reviews),
                        selectinload(ProductModel.sellers),
                        selectinload(ProductModel.categories),
                        selectinload(ProductModel.images),
                    )
                )
                .scalars()
                .first()
            )
            return to_product_type(product) if product else None
        finally:
            db.close()


